4.1 Very wide data

gh_repos. This is a list that contains data about a collection of GitHub repositories retrieved using the GitHub API.



Code
library(repurrrsive)
#view(gh_repos)

repos &lt;- tibble(json = gh_repos)
repos









Code
repos |&gt;
  unnest_longer(json)









Code
repos |&gt;
  unnest_longer(json) |&gt;
  unnest_wider(json)









Code
repos |&gt;
  unnest_longer(json) |&gt;
  unnest_wider(json) |&gt;
  names() |&gt;
  head(10)


 [1] "id"          "name"        "full_name"   "owner"       "private"    
 [6] "html_url"    "description" "fork"        "url"         "forks_url"  




Code
repos |&gt;
  unnest_longer(json) |&gt;
  unnest_wider(json) |&gt;
  select(id, full_name, owner, description)









Code
repos |&gt;
  unnest_longer(json) |&gt;
  unnest_wider(json) |&gt;
  select(id, full_name, owner, description) |&gt;
  unnest_wider(owner)


Output:
Error in `unnest_wider()` at w09-hierarchical-data/ch23/draft-hierarchical-data-0.qmd:301:1:
! Can't duplicate names between the affected columns and the original data.
✖ These names are duplicated:
  ℹ `id`, from `owner`.
ℹ Use `names_sep` to disambiguate using the column name.


Code
repos |&gt;
  unnest_longer(json) |&gt;
  unnest_wider(json) |&gt;
  select(id, full_name, owner, description) |&gt;
  unnest_wider(owner, names_sep = "_")

4.2 Relational data

Nested data is sometimes used to represent data that we’d usually spread across multiple data frames.


Example: got_chars which contains data about characters that appear in the Game of Thrones books and TV series.



Code
chars &lt;- tibble(json = got_chars)
chars







Code
# Widening
chars |&gt;
  unnest_wider(json)







Code
# selecting a few
chars |&gt;
  unnest_wider(json) |&gt;
  select(id, name, gender, culture, born, died, alive)







Code
# search for list-columns
chars |&gt;
  unnest_wider(json) |&gt;
  select(id, where(is.list))







Code
# explore titles column
chars |&gt;
  unnest_wider(json) |&gt;
  select(id, titles) |&gt;
  unnest_longer(titles)







Code
# cleanning
titles &lt;- chars |&gt;
  unnest_wider(json) |&gt;
  select(id, titles) |&gt;
  unnest_longer(titles) |&gt;
  filter(titles != "") |&gt;
  rename(title = titles)

titles








You could imagine creating a table like this for each of the list-columns, then using joins to combine them with the character data as you need it.

4.3 Deeply nested

When the data is very deeply nested and requires repeated rounds of unnest_wider() and unnest_longer() to unravel: gmaps_cities.



Code
gmaps_cities









Code
gmaps_cities |&gt;
  unnest_wider(json)









Drop the status column since they’re all OK




Unnamed list




Code
gmaps_cities |&gt;
  unnest_wider(json) |&gt;
  select(-status) |&gt;
  unnest_longer(results)








Now results is a named list, so we’ll use unnest_wider():



Code
locations &lt;- gmaps_cities |&gt;
  unnest_wider(json) |&gt;
  select(-status) |&gt;
  unnest_longer(results) |&gt;
  unnest_wider(results)

locations








There are a few different places we could go from here. We might want to determine the exact location of the match, which is stored in the geometry list-column:



Code
locations |&gt;
  select(city, formatted_address, geometry) |&gt;
  unnest_wider(geometry)








We can unnest location to see the latitude (lat) and longitude (lng):



Code
locations |&gt;
  select(city, formatted_address, geometry) |&gt;
  unnest_wider(geometry) |&gt;
  unnest_wider(location)








Extracting the bounds requires a few more steps:



Code
locations |&gt;
  select(city, formatted_address, geometry) |&gt;
  unnest_wider(geometry) |&gt;
  # focus on the variables of interest
  select(!location:viewport) |&gt;
  unnest_wider(bounds)








We then rename southwest and northeast (the corners of the rectangle) so we can use names_sep to create short but evocative names:



Code
locations |&gt;
  select(city, formatted_address, geometry) |&gt;
  unnest_wider(geometry) |&gt;
  select(!location:viewport) |&gt;
  unnest_wider(bounds) |&gt;
  rename(ne = northeast, sw = southwest) |&gt;
  unnest_wider(c(ne, sw), names_sep = "_")








Once you’ve discovered the path to get to the components you’re interested in, you can extract them directly using another tidyr function, hoist():



Code
locations |&gt;
  select(city, formatted_address, geometry) |&gt;
  hoist(
    geometry,
    ne_lat = c("bounds", "northeast", "lat"),
    sw_lat = c("bounds", "southwest", "lat"),
    ne_lng = c("bounds", "northeast", "lng"),
    sw_lng = c("bounds", "southwest", "lng"),
  )

4.5 Exercises

Roughly estimate when gh_repos was created. Why can you only roughly estimate the date?
The owner column of gh_repos contains a lot of duplicated information because each owner can have many repos. Can you construct an owners data frame that contains one row for each owner? (Hint: does distinct() work with list-cols?)
Follow the steps used for titles to create similar tables for the aliases, allegiances, books, and TV series for the Game of Thrones characters.
Explain the following code line-by-line. Why is it interesting? Why does it work for got_chars but might not work in general?



Code
tibble(json = got_chars) |&gt;
  unnest_wider(json) |&gt;
  select(id, where(is.list)) |&gt;
  pivot_longer(
    where(is.list),
    names_to = "name",
    values_to = "value"
  ) |&gt;
  unnest_longer(value)








In gmaps_cities, what does address_components contain? Why does the length vary between rows? Unnest it appropriately to figure it out. (Hint: types always appears to contain two elements. Does unnest_wider() make it easier to work with than unnest_longer()?) .

5.3 Starting the rectangling process

In most cases, JSON files contain a single top-level array



Code
json &lt;- '[
  {"name": "John", "age": 34},
  {"name": "Susan", "age": 27}
]'

df &lt;- tibble(json = parse_json(json))
df









Code
df |&gt;
  unnest_wider(json)








In rarer cases, the JSON file consists of a single top-level JSON object, representing one “thing”. In this case, you’ll need to kick off the rectangling process by wrapping it in a list, before you put it in a tibble.



Code
json &lt;- '{
  "status": "OK", 
  "results": [
    {"name": "John", "age": 34},
    {"name": "Susan", "age": 27}
 ]
}
'
df &lt;- tibble(json = list(parse_json(json)))
df









Code
df |&gt;
  unnest_wider(json) |&gt;
  unnest_longer(results) |&gt;
  unnest_wider(results)








Alternatively, you can reach inside the parsed JSON and start with the bit that you actually care about:



Code
df &lt;- tibble(results = parse_json(json)$results)
df |&gt;
  unnest_wider(results)

1.2 Analysis 1: Traffic Source Performance
Marketing Question: Which channels are driving the most engaged traffic?


Code
traffic_analysis &lt;- ga4_master |&gt;
  filter(event_name == "user_engagement") |&gt;
  mutate(
    # Clean and standardise channel labels
    medium = case_when(
      is.na(traffic_source_medium) ~ "(none)",
      traffic_source_medium == "(none)" ~ "direct",
      traffic_source_medium == "organic" ~ "organic search",
      traffic_source_medium %in% c("cpc", "ppc", "paid") ~ "paid search",
      str_detect(traffic_source_medium, "email") ~ "email",
      str_detect(
        traffic_source_medium,
        "social|referral"
      ) ~ traffic_source_medium,
      TRUE ~ traffic_source_medium
    )
  ) |&gt;
  group_by(medium) |&gt;
  summarise(
    sessions = n(),
    unique_users = n_distinct(user_pseudo_id),
    .groups = "drop"
  ) |&gt;
  # Join in engagement and conversion metrics from full event stream
  left_join(
    ga4_master |&gt;
      filter(event_name == "session_start") |&gt;
      mutate(
        medium = case_when(
          is.na(traffic_source_medium) ~ "(none)",
          traffic_source_medium == "(none)" ~ "direct",
          traffic_source_medium == "organic" ~ "organic search",
          traffic_source_medium %in% c("cpc", "ppc", "paid") ~ "paid search",
          str_detect(traffic_source_medium, "email") ~ "email",
          TRUE ~ traffic_source_medium
        )
      ) |&gt;
      group_by(medium, user_pseudo_id) |&gt;
      summarise(.groups = "drop") |&gt;
      left_join(
        ga4_master |&gt;
          filter(event_name == "purchase") |&gt;
          distinct(user_pseudo_id) |&gt;
          mutate(converted = TRUE),
        by = "user_pseudo_id"
      ) |&gt;
      group_by(medium) |&gt;
      summarise(
        users_who_purchased = sum(!is.na(converted)),
        .groups = "drop"
      ),
    by = "medium"
  ) |&gt;
  mutate(
    conversion_rate = users_who_purchased / unique_users,
    sessions_pct = sessions / sum(sessions)
  ) |&gt;
  arrange(desc(sessions))

traffic_analysis









Code
# ── Panel A: Session Volume by Channel ────────────────────────────────────────
library(scales)
p1 &lt;- traffic_analysis |&gt;
  filter(sessions &gt; 10) |&gt;
  mutate(medium = fct_reorder(medium, sessions)) |&gt;
  ggplot(aes(x = medium, y = sessions, fill = medium)) +
  geom_col(show.legend = FALSE, width = 0.65) +
  geom_text(
    aes(label = comma(sessions)),
    hjust = -0.15,
    size = 3.5
  ) +
  coord_flip() +
  scale_y_continuous(
    labels = comma,
    expand = expansion(mult = c(0, 0.18))
  ) +
  scale_fill_brewer(palette = "Set2") +
  labs(
    title = "Sessions by Traffic Channel",
    subtitle = "Jan 1–7, 2021 · Google Merchandise Store",
    x = NULL,
    y = "Sessions"
  )

# ── Panel B: Conversion Rate by Channel ───────────────────────────────────────
p2 &lt;- traffic_analysis |&gt;
  filter(sessions &gt; 10, !is.na(conversion_rate)) |&gt;
  mutate(medium = fct_reorder(medium, conversion_rate)) |&gt;
  ggplot(aes(x = medium, y = conversion_rate, fill = medium)) +
  geom_col(show.legend = FALSE, width = 0.65) +
  geom_text(
    aes(label = percent(conversion_rate, accuracy = 0.1)),
    hjust = -0.15,
    size = 3.5
  ) +
  coord_flip() +
  scale_y_continuous(
    labels = percent,
    expand = expansion(mult = c(0, 0.22))
  ) +
  scale_fill_brewer(palette = "Set2") +
  labs(
    title = "Purchase Conversion Rate by Channel",
    subtitle = "Users who completed a purchase ÷ users who started a session",
    x = NULL,
    y = "Conversion Rate"
  )

# Display side by side using patchwork if available, else stacked
if (requireNamespace("patchwork", quietly = TRUE)) {
  library(patchwork)
  p1 + p2
} else {
  print(p1)
  print(p2)
}















TipMarketing Interpretation




Volume vs. quality: The channel with the most sessions is not necessarily the best performer. Compare session volume against conversion rate to identify high-value channels.
Direct traffic often represents users who already know the brand — expect higher conversion rates.
Organic search volume indicates SEO health; low conversion from organic can signal a landing page or audience-fit problem.

1.4 Analysis 3: Content Performance
Marketing Question: Which pages attract the most traffic, and how do users navigate the site?
This analysis requires extracting page_location from event_params — a direct application of the key-value pipeline we built in Part 2.


Code
page_views &lt;- ga4_master |&gt;
  filter(event_name == "page_view", !is.na(page_location)) |&gt;
  mutate(
    # Parse the URL path from the full URL
    page_path = str_remove(page_location, "^https?://[^/]+"),
    page_path = str_remove(page_path, "\\?.*$"), # Remove query strings
    page_path = str_remove(page_path, "#.*$"), # Remove anchors
    page_path = if_else(page_path == "" | is.na(page_path), "/", page_path),

    # Categorise pages into sections for rolled-up analysis
    page_section = case_when(
      page_path == "/" ~ "Home",
      str_detect(page_path, "^/google\\+re|^/store|^/shop") ~ "Store",
      str_detect(page_path, "^/product") ~ "Product Pages",
      str_detect(page_path, "^/basket|^/cart") ~ "Cart",
      str_detect(page_path, "^/checkout") ~ "Checkout",
      str_detect(page_path, "^/signin|^/log") ~ "Sign In",
      str_detect(page_path, "^/brands") ~ "Brands",
      TRUE ~ "Other"
    )
  )

# Top individual pages
top_pages &lt;- page_views |&gt;
  count(page_path, page_section, sort = TRUE) |&gt;
  slice_head(n = 20)

# Page section rollup
section_rollup &lt;- page_views |&gt;
  count(page_section, sort = TRUE) |&gt;
  mutate(
    pct = n / sum(n),
    page_section = fct_reorder(page_section, n)
  )




Code
top_pages |&gt;
  slice_head(n = 15) |&gt;
  mutate(
    page_path = str_trunc(page_path, 45),
    page_path = fct_reorder(page_path, n)
  ) |&gt;
  ggplot(aes(x = page_path, y = n, fill = page_section)) +
  geom_col(width = 0.7) +
  geom_text(
    aes(label = comma(n)),
    hjust = -0.15,
    size = 3.5
  ) +
  coord_flip() +
  scale_y_continuous(
    labels = comma,
    expand = expansion(mult = c(0, 0.18))
  ) +
  scale_fill_brewer(palette = "Set2", name = "Section") +
  labs(
    title = "Top 15 Pages by Page Views",
    subtitle = "Jan 1–7, 2021 · Colour = site section",
    x = NULL,
    y = "Page Views"
  ) +
  theme(legend.position = "bottom")











Code
section_rollup |&gt;
  ggplot(aes(x = page_section, y = n, fill = page_section)) +
  geom_col(show.legend = FALSE, width = 0.65) +
  geom_text(
    aes(label = glue("{comma(n)}\n{percent(pct, accuracy = 0.1)}")),
    vjust = -0.4,
    size = 3.5,
    lineheight = 0.9
  ) +
  scale_y_continuous(
    labels = comma,
    expand = expansion(mult = c(0, 0.2))
  ) +
  scale_fill_brewer(palette = "Paired") +
  labs(
    title = "Page Views by Site Section",
    subtitle = "Rolled-up view using URL path categorisation",
    x = NULL,
    y = "Page Views"
  )




Code
# What external pages referred traffic to the site?
top_referrers &lt;- ga4_master |&gt;
  filter(
    event_name == "page_view",
    !is.na(page_referrer),
    page_referrer != "",
    !str_detect(page_referrer, "google\\.com/merchandise|merch\\.google")
  ) |&gt;
  mutate(
    referrer_domain = str_extract(page_referrer, "(?&lt;=://)[^/]+"),
    referrer_domain = str_remove(referrer_domain, "^www\\.")
  ) |&gt;
  count(referrer_domain, sort = TRUE) |&gt;
  filter(!is.na(referrer_domain)) |&gt;
  slice_head(n = 10)

top_referrers |&gt;
  gt() |&gt;
  tab_header(
    title = "Top 10 Referring Domains",
    subtitle = "External sites sending traffic to Google Merchandise Store"
  ) |&gt;
  fmt_number(columns = n, decimals = 0) |&gt;
  cols_label(referrer_domain = "Referring Domain", n = "Referrals") |&gt;
  opt_stylize(style = 1)

1.5 Analysis 4: E-commerce Funnel
Marketing Question: Where in the purchase funnel are we losing customers?


Code
# Define funnel stages and their GA4 event names
funnel_stages &lt;- tibble(
  stage_order = 1:6,
  event_name = c(
    "view_item",
    "add_to_cart",
    "view_cart",
    "begin_checkout",
    "add_payment_info",
    "purchase"
  ),
  stage_label = c(
    "View Item",
    "Add to Cart",
    "View Cart",
    "Begin Checkout",
    "Add Payment Info",
    "Purchase"
  )
)

# Count unique users at each funnel stage
funnel_data &lt;- funnel_stages |&gt;
  left_join(
    ga4_master |&gt;
      filter(event_name %in% funnel_stages$event_name) |&gt;
      group_by(event_name) |&gt;
      summarise(users = n_distinct(user_pseudo_id), .groups = "drop"),
    by = "event_name"
  ) |&gt;
  arrange(stage_order) |&gt;
  mutate(
    users = replace_na(users, 0),
    top_users = max(users),
    pct_of_top = users / top_users,
    pct_prev = users / lag(users), # Drop-off to previous stage
    drop_off = 1 - pct_prev
  )

funnel_data |&gt;
  select(stage_label, users, pct_of_top, pct_prev, drop_off) |&gt;
  gt() |&gt;
  tab_header(
    title = "Purchase Funnel Analysis",
    subtitle = "Unique users reaching each stage · Jan 1–7, 2021"
  ) |&gt;
  fmt_number(columns = users, decimals = 0) |&gt;
  fmt_percent(columns = c(pct_of_top, pct_prev, drop_off), decimals = 1) |&gt;
  cols_label(
    stage_label = "Funnel Stage",
    users = "Users",
    pct_of_top = "% of Top Stage",
    pct_prev = "Retained from Prior",
    drop_off = "Drop-off Rate"
  ) |&gt;
  data_color(
    columns = drop_off,
    method = "numeric",
    palette = c("#ffffff", "#f4433620"),
    na_color = "white"
  ) |&gt;
  sub_missing(missing_text = "—") |&gt;
  opt_stylize(style = 1)




Code
funnel_data |&gt;
  mutate(stage_label = fct_inorder(stage_label)) |&gt;
  ggplot(aes(x = stage_label, y = users)) +
  geom_col(
    aes(fill = pct_of_top),
    width = 0.75,
    show.legend = FALSE
  ) +
  geom_text(
    aes(
      label = glue(
        "{comma(users)} users\n({percent(pct_of_top, accuracy=0.1)})"
      )
    ),
    vjust = -0.4,
    size = 3.5,
    lineheight = 0.85,
    fontface = "bold"
  ) +
  # Annotate drop-off rates between bars
  geom_text(
    data = funnel_data |&gt; filter(!is.na(drop_off)),
    aes(
      x = as.numeric(fct_inorder(stage_label)) - 0.5,
      y = max(funnel_data$users) * 0.55,
      label = glue("▼ {percent(drop_off, accuracy=1)}\ndrop-off")
    ),
    size = 3,
    colour = "#e53935",
    lineheight = 0.85
  ) +
  scale_y_continuous(
    labels = comma,
    expand = expansion(mult = c(0, 0.2))
  ) +
  scale_fill_gradient(low = "#bbdefb", high = "#1565c0") +
  labs(
    title = "Purchase Funnel: Users by Stage",
    subtitle = "Jan 1–7, 2021 · Google Merchandise Store",
    x = NULL,
    y = "Unique Users"
  ) +
  theme(axis.text.x = element_text(size = 10))




Code
library(gt)
# Revenue analysis using the flattened ecommerce struct
revenue_daily &lt;- ga4_master |&gt;
  filter(event_name == "purchase") |&gt;
  group_by(event_date) |&gt;
  summarise(
    transactions = n(),
    total_revenue = sum(
      as.numeric(ecommerce_purchase_revenue_in_usd),
      na.rm = TRUE
    ),
    avg_order_value = mean(
      as.numeric(ecommerce_purchase_revenue_in_usd),
      na.rm = TRUE
    ),
    unique_buyers = n_distinct(user_pseudo_id),
    .groups = "drop"
  )

revenue_daily |&gt;
  gt() |&gt;
  tab_header(
    title = "Daily Revenue Summary",
    subtitle = "Derived from ecommerce struct (Pattern 1 unnesting)"
  ) |&gt;
  fmt_date(columns = event_date, date_style = "day_m_year") |&gt;
  fmt_number(columns = transactions, decimals = 0) |&gt;
  fmt_currency(columns = c(total_revenue, avg_order_value), currency = "USD") |&gt;
  fmt_number(columns = unique_buyers, decimals = 0) |&gt;
  cols_label(
    event_date = "Date",
    transactions = "Transactions",
    total_revenue = "Revenue",
    avg_order_value = "Avg. Order Value",
    unique_buyers = "Unique Buyers"
  ) |&gt;
  grand_summary_rows(
    columns = c(transactions, total_revenue, unique_buyers),
    fns = list(Total = ~ sum(., na.rm = TRUE)),
    fmt = list(
      ~ fmt_number(., columns = c(transactions, unique_buyers), decimals = 0),
      ~ fmt_currency(., columns = total_revenue, currency = "USD")
    )
  ) |&gt;
  opt_stylize(style = 1)




Code
revenue_daily |&gt;
  ggplot(aes(x = event_date)) +
